const results = [];
const rawInputs = $input.all();
const sourceItems = $("Find Posts to Script").all();
const sourceCount = sourceItems.length;

if (sourceCount === 0) return [];

for (let i = 0; i < rawInputs.length; i++) {
  const item = rawInputs[i];
  // FIX: read from output first — that is where chainLlm stores the actual Gemini response
  let raw = item.json.output || item.json.text || '{}';
  let parsed = {};
  try {
    parsed = JSON.parse(raw);
  } catch (e) {
    const match = raw.match(/\{[^]*\}/);
    if (match) { try { parsed = JSON.parse(match[0]); } catch {} }
  }

  // Identify source record
  const sourceIndex = i % sourceCount;
  const sourceRecord = sourceItems[sourceIndex]?.json || {};

  // FORCE CORRECT PLATFORM: Items 0 to sourceCount-1 are LinkedIn, the rest are Facebook
  const platform = (i < sourceCount) ? 'LinkedIn' : 'Facebook';

  const title = parsed.title || parsed.Name || sourceRecord.Name || 'Untitled Script';

  // CHECK FOR DIRTY PLACEHOLDERS in the actual Gemini response
  const hasPlaceholders = raw.includes('{{') || raw.includes('$json');

  // FIX: skip bad scripts entirely — never save them to Airtable
  if (hasPlaceholders) continue;

  results.push({
    json: {
      Name: title,
      Source_Content_ID: [sourceRecord.id],
      Script_Title: title,
      Target_Platforms: platform,
      Hook: parsed.hook || '',
      Main_Content: parsed.body || '',
      CTA: parsed.cta || '',
      Status: 'Draft',
      Created_Date: new Date().toISOString().slice(0, 10)
    }
  });
}

return results;
